-- Chapter 10: Circular Motion
INSERT INTO concept_exercises (chapter, title, text_pdf_url, page_offset, sections, answer_key)
VALUES (10, $ch10$Circular Motion$ch10$, $ch10$https://ymszffulqmkqgvhioege.supabase.co/storage/v1/object/public/lesson-media/cpte10.pdf$ch10$, 169,
$ch10$[{"id": "10.1", "label": "Rotation and Revolution", "pageStart": 171, "pageEnd": 171, "items": [{"n": 1, "type": "fill_in", "prompt": "The straight line around which rotation takes place is called the ______.", "blanks": 1}, {"n": 2, "type": "fill_in", "prompt": "When an object turns about an internal axis, the motion is called ______; when it turns about an external axis, the motion is called ______.", "blanks": 2}, {"n": 3, "type": "true_false", "prompt": "Although a Ferris wheel rotates, the riders revolve about its axis."}, {"n": 4, "type": "multiple_choice", "prompt": "Earth rotates around an axis passing through its geographical poles once every", "options": [{"letter": "a", "text": "24 hours"}, {"letter": "b", "text": "30 days"}, {"letter": "c", "text": "365 1/4 days"}]}, {"n": 5, "type": "short_answer", "prompt": "What are the two types of circular motion?"}]}, {"id": "10.2", "label": "Rotational Speed", "pageStart": 171, "pageEnd": 174, "items": [{"n": 6, "type": "fill_in", "prompt": "______ speed is the number of rotations per unit of time, commonly expressed in revolutions per minute (RPM).", "blanks": 1}, {"n": 7, "type": "fill_in", "prompt": "The speed of something moving along a circular path is called ______ speed because the direction of motion is always ______ to the circle.", "blanks": 2}, {"n": 8, "type": "true_false", "prompt": "All parts of a rigidly rotating system, such as a merry-go-round, have the same rotational speed."}, {"n": 9, "type": "true_false", "prompt": "A ladybug sitting at the outer edge of a turntable has the same tangential speed as one sitting near the center."}, {"n": 10, "type": "multiple_choice", "prompt": "Tangential speed is directly proportional to", "options": [{"letter": "a", "text": "rotational speed only"}, {"letter": "b", "text": "radial distance only"}, {"letter": "c", "text": "both rotational speed and radial distance from the axis"}]}, {"n": 11, "type": "short_answer", "prompt": "Why does a moving train stay on its tracks even though the wheel flanges are rarely used?"}]}, {"id": "10.3", "label": "Centripetal Force", "pageStart": 175, "pageEnd": 177, "items": [{"n": 12, "type": "fill_in", "prompt": "Centripetal means “toward the ______.”", "blanks": 1}, {"n": 13, "type": "fill_in", "prompt": "When an automobile rounds a corner, ______ between the tires and the road provides the centripetal force that holds the car in a curved path.", "blanks": 1}, {"n": 14, "type": "true_false", "prompt": "Centripetal force is a basic force of nature, like gravity."}, {"n": 15, "type": "multiple_choice", "prompt": "According to Fc = mv²/r, traveling in a circular path with a smaller radius of curvature requires", "options": [{"letter": "a", "text": "less centripetal force"}, {"letter": "b", "text": "greater centripetal force"}, {"letter": "c", "text": "the same centripetal force"}]}, {"n": 16, "type": "short_answer", "prompt": "In the spin cycle of an automatic washer, what happens to the water in the wet clothes?"}]}, {"id": "10.4", "label": "Centripetal and Centrifugal Forces", "pageStart": 178, "pageEnd": 179, "items": [{"n": 17, "type": "fill_in", "prompt": "Centrifugal means “center-______,” or “away from the center.”", "blanks": 1}, {"n": 18, "type": "fill_in", "prompt": "When the string holding a whirling can breaks, the can goes off in a ______ straight-line path because no force acts on it.", "blanks": 1}, {"n": 19, "type": "true_false", "prompt": "When you swing a tin can in a circular path, a centrifugal force pulls outward on the can."}, {"n": 20, "type": "true_false", "prompt": "When a car rounds a sharp corner, you pitch against the door because there is no centripetal force holding you in circular motion."}, {"n": 21, "type": "multiple_choice", "prompt": "The “centrifugal-force effect” is attributed to", "options": [{"letter": "a", "text": "a real outward force"}, {"letter": "b", "text": "inertia—the tendency of the moving body to follow a straight-line path"}, {"letter": "c", "text": "gravity acting sideways"}]}]}, {"id": "10.5", "label": "Centrifugal Force in a Rotating Reference Frame", "pageStart": 179, "pageEnd": 180, "items": [{"n": 22, "type": "fill_in", "prompt": "In the rotating frame of reference of a whirling can, both centripetal force and ______ force appear to act on a ladybug inside.", "blanks": 1}, {"n": 23, "type": "fill_in", "prompt": "Because centrifugal force is not part of an interaction, physicists call it a ______ force.", "blanks": 1}, {"n": 24, "type": "true_false", "prompt": "Gravitational force is always an interaction between one mass and another."}, {"n": 25, "type": "multiple_choice", "prompt": "Centrifugal force differs from gravitational force in that centrifugal force", "options": [{"letter": "a", "text": "has no interaction counterpart—no mass out there pulling on it"}, {"letter": "b", "text": "is much stronger than gravity"}, {"letter": "c", "text": "acts only on small objects"}]}, {"n": 26, "type": "short_answer", "prompt": "From a stationary frame of reference outside a whirling can, what force acts on the ladybug inside?"}]}]$ch10$::jsonb,
$ch10${"1": ["axis"], "2": ["rotation", "revolution"], "3": "true", "4": "a", "5": {"model": "The two types of circular motion are rotation (turning about an internal axis) and revolution (turning about an external axis)."}, "6": ["rotational"], "7": ["tangential", "tangent"], "8": "true", "9": "false", "10": "c", "11": {"model": "Train wheel rims are slightly tapered, so when the pair rolls off center the wider part of one wheel travels faster and steers the wheels back toward the center of the track."}, "12": ["center"], "13": ["friction"], "14": "false", "15": "b", "16": {"model": "The tub's wall forces the clothes into a circular path, but the water escapes tangentially out the holes in the wall—the clothes are forced away from the water."}, "17": ["fleeing"], "18": ["tangential"], "19": "false", "20": "true", "21": "b", "22": ["centrifugal"], "23": ["fictitious"], "24": "true", "25": "a", "26": {"model": "Only a centripetal force (the can pressing on the ladybug) acts; no centrifugal force acts on her in the stationary frame."}}$ch10$::jsonb)
ON CONFLICT (chapter) DO UPDATE SET title=EXCLUDED.title, text_pdf_url=EXCLUDED.text_pdf_url, page_offset=EXCLUDED.page_offset, sections=EXCLUDED.sections, answer_key=EXCLUDED.answer_key, updated_at=now();

-- Chapter 13: Universal Gravitation
INSERT INTO concept_exercises (chapter, title, text_pdf_url, page_offset, sections, answer_key)
VALUES (13, $ch13$Universal Gravitation$ch13$, $ch13$https://ymszffulqmkqgvhioege.supabase.co/storage/v1/object/public/lesson-media/cpte13.pdf$ch13$, 231,
$ch13$[{"id": "13.1", "label": "The Falling Apple", "pageStart": 233, "pageEnd": 233, "items": [{"n": 1, "type": "fill_in", "prompt": "Newton understood the concept of ______ developed earlier by Galileo: without an outside force, moving objects continue at constant speed in a straight line.", "blanks": 1}, {"n": 2, "type": "fill_in", "prompt": "Newton reasoned that the moon is falling toward Earth for the same reason an apple falls from a tree—both are pulled by Earth's ______.", "blanks": 1}, {"n": 3, "type": "true_false", "prompt": "Newton knew that circular motion is accelerated motion, which requires a force."}, {"n": 4, "type": "multiple_choice", "prompt": "According to popular legend, the idea that gravity extends throughout the universe occurred to Newton while he was", "options": [{"letter": "a", "text": "sailing across the ocean"}, {"letter": "b", "text": "sitting underneath an apple tree"}, {"letter": "c", "text": "observing a solar eclipse"}]}]}, {"id": "13.2", "label": "The Falling Moon", "pageStart": 233, "pageEnd": 235, "items": [{"n": 5, "type": "fill_in", "prompt": "Newton compared the motion of the moon to a ______ fired from the top of a high mountain.", "blanks": 1}, {"n": 6, "type": "fill_in", "prompt": "The sideways component of velocity, parallel to Earth's surface, is called ______ velocity.", "blanks": 1}, {"n": 7, "type": "true_false", "prompt": "Newton realized that if the moon did not fall, it would move off in a straight line and leave its orbit."}, {"n": 8, "type": "true_false", "prompt": "Newton published his moon calculation immediately after making it."}, {"n": 9, "type": "multiple_choice", "prompt": "The moon is 60 times farther from Earth's center than an apple at Earth's surface, so in one second the moon should fall", "options": [{"letter": "a", "text": "1/60 of 5 m"}, {"letter": "b", "text": "1/(60)² of 5 m, about 1.4 millimeters"}, {"letter": "c", "text": "the same 5 m an apple falls"}]}, {"n": 10, "type": "short_answer", "prompt": "Why doesn't the moon hit Earth?"}]}, {"id": "13.3", "label": "The Falling Earth", "pageStart": 236, "pageEnd": 236, "items": [{"n": 11, "type": "fill_in", "prompt": "Newton's theory of gravity confirmed the ______ theory of the solar system.", "blanks": 1}, {"n": 12, "type": "fill_in", "prompt": "The planets continually “______” around the sun in closed paths.", "blanks": 1}, {"n": 13, "type": "true_false", "prompt": "If the tangential velocities of the planets were reduced to zero, they would crash straight into the sun."}, {"n": 14, "type": "multiple_choice", "prompt": "In the view of the solar system confirmed by Newton's theory of gravity, the center of the solar system is occupied by", "options": [{"letter": "a", "text": "Earth"}, {"letter": "b", "text": "the sun"}, {"letter": "c", "text": "the moon"}]}]}, {"id": "13.4", "label": "Newton's Law of Universal Gravitation", "pageStart": 237, "pageEnd": 239, "items": [{"n": 15, "type": "fill_in", "prompt": "Newton did not discover gravity—he discovered that gravity is ______.", "blanks": 1}, {"n": 16, "type": "fill_in", "prompt": "In the equation F = G(m₁m₂/d²), d is the distance between the objects' ______.", "blanks": 1}, {"n": 17, "type": "true_false", "prompt": "The small value of G tells us that gravity is the weakest of the presently known four fundamental forces."}, {"n": 18, "type": "true_false", "prompt": "At the top of a mountain your mass is the same as anywhere else, but your weight is slightly less than at ground level."}, {"n": 19, "type": "multiple_choice", "prompt": "G was first measured 150 years after Newton's discovery of universal gravitation by", "options": [{"letter": "a", "text": "Henry Cavendish"}, {"letter": "b", "text": "Edmund Halley"}, {"letter": "c", "text": "Galileo Galilei"}]}, {"n": 20, "type": "short_answer", "prompt": "Why was Cavendish's first measurement of G called the “Weighing the Earth” experiment?"}]}, {"id": "13.5", "label": "Gravity and Distance: The Inverse-Square Law", "pageStart": 240, "pageEnd": 241, "items": [{"n": 21, "type": "fill_in", "prompt": "When a quantity varies as the inverse square of its distance from its source, it follows an ______-______ law.", "blanks": 2}, {"n": 22, "type": "fill_in", "prompt": "An apple that weighs 1 N at Earth's surface weighs only ______ N when it is twice as far from Earth's center.", "blanks": 1}, {"n": 23, "type": "true_false", "prompt": "If you were transported to the far reaches of the universe, the gravitational influence of Earth on you would drop to zero."}, {"n": 24, "type": "multiple_choice", "prompt": "In the butter-gun analogy, when the toast is held three times as far from the gun, the butter layer on each piece is", "options": [{"letter": "a", "text": "1/3 as thick"}, {"letter": "b", "text": "1/9 as thick"}, {"letter": "c", "text": "9 times as thick"}]}, {"n": 25, "type": "short_answer", "prompt": "Besides gravity and the butter gun, name two other effects that spread out according to the inverse-square law."}]}, {"id": "13.6", "label": "Gravitational Field", "pageStart": 242, "pageEnd": 243, "items": [{"n": 26, "type": "fill_in", "prompt": "A gravitational field is an example of a ______ field, because any mass in the field space experiences a force.", "blanks": 1}, {"n": 27, "type": "fill_in", "prompt": "Field lines are ______ together where the gravitational field is stronger.", "blanks": 1}, {"n": 28, "type": "true_false", "prompt": "The strength of Earth's gravitational field follows the inverse-square law."}, {"n": 29, "type": "multiple_choice", "prompt": "Iron filings sprinkled over a sheet of paper on top of a magnet reveal", "options": [{"letter": "a", "text": "the mass of the magnet"}, {"letter": "b", "text": "the shape of the magnet's magnetic field"}, {"letter": "c", "text": "the electric charge of the magnet"}]}, {"n": 30, "type": "short_answer", "prompt": "Where is Earth's gravitational field strongest?"}]}, {"id": "13.7", "label": "Gravitational Field Inside a Planet", "pageStart": 244, "pageEnd": 244, "items": [{"n": 31, "type": "fill_in", "prompt": "The gravitational field of Earth at its center is ______.", "blanks": 1}, {"n": 32, "type": "fill_in", "prompt": "Without air drag, a trip through a hole bored completely through Earth would take nearly ______ minutes from one end to the other.", "blanks": 1}, {"n": 33, "type": "true_false", "prompt": "As you fall toward the center of Earth, your acceleration progressively increases."}, {"n": 34, "type": "true_false", "prompt": "Falling into a hole through Earth, you would gain speed all the way to the center and lose speed moving away from the center."}, {"n": 35, "type": "multiple_choice", "prompt": "At the center of Earth your weight would be zero because", "options": [{"letter": "a", "text": "gravity does not exist there"}, {"letter": "b", "text": "you are pulled equally by gravity in every direction, so the net force is zero"}, {"letter": "c", "text": "you would be moving too fast to be weighed"}]}]}, {"id": "13.8", "label": "Weight and Weightlessness", "pageStart": 245, "pageEnd": 246, "items": [{"n": 36, "type": "fill_in", "prompt": "Force against Earth is the sensation we interpret as ______.", "blanks": 1}, {"n": 37, "type": "fill_in", "prompt": "The condition of weightlessness is not the absence of gravity; it is the absence of a ______ force.", "blanks": 1}, {"n": 38, "type": "true_false", "prompt": "If an elevator accelerates upward while you stand on a bathroom scale, the scale shows an increase in your weight."}, {"n": 39, "type": "multiple_choice", "prompt": "Astronauts in orbit experience weightlessness because they", "options": [{"letter": "a", "text": "are beyond the pull of Earth's gravity"}, {"letter": "b", "text": "are without a support force"}, {"letter": "c", "text": "have lost their mass"}]}, {"n": 40, "type": "short_answer", "prompt": "How can future space stations provide their occupants with weight?"}]}, {"id": "13.9", "label": "Ocean Tides", "pageStart": 246, "pageEnd": 248, "items": [{"n": 41, "type": "fill_in", "prompt": "Newton showed that ocean tides are caused by ______ in the gravitational pull of the moon on opposite sides of Earth.", "blanks": 1}, {"n": 42, "type": "fill_in", "prompt": "A ______ tide occurs when the sun, Earth, and moon are all lined up; a ______ tide occurs when the moon is halfway between a new moon and a full moon.", "blanks": 2}, {"n": 43, "type": "true_false", "prompt": "Because Earth spins beneath the two tidal bulges, there are two high tides and two low tides each day."}, {"n": 44, "type": "true_false", "prompt": "Tides due to the sun are 180 times greater than lunar tides because the sun's pull on Earth is 180 times greater than the moon's."}, {"n": 45, "type": "multiple_choice", "prompt": "Spring tides occur at the times of", "options": [{"letter": "a", "text": "a half moon"}, {"letter": "b", "text": "a new moon or a full moon"}, {"letter": "c", "text": "the spring season only"}]}, {"n": 46, "type": "short_answer", "prompt": "Why does the moon produce scarcely any tides in a lake?"}]}, {"id": "13.10", "label": "Black Holes", "pageStart": 249, "pageEnd": 251, "items": [{"n": 47, "type": "fill_in", "prompt": "The size of the sun is the result of a “tug of war” between gravitation and thermonuclear ______.", "blanks": 1}, {"n": 48, "type": "fill_in", "prompt": "Gravitation near a black hole is so enormous that nothing—not even ______—can escape.", "blanks": 1}, {"n": 49, "type": "true_false", "prompt": "A black hole is more massive than the star from which it collapsed."}, {"n": 50, "type": "multiple_choice", "prompt": "When a massive star collapses into a black hole, the gravitational field at points beyond the star's original radius", "options": [{"letter": "a", "text": "increases enormously"}, {"letter": "b", "text": "drops to zero"}, {"letter": "c", "text": "does not change"}]}, {"n": 51, "type": "short_answer", "prompt": "Black holes can't be seen, so how can their effects be detected?"}]}, {"id": "13.11", "label": "Universal Gravitation", "pageStart": 251, "pageEnd": 254, "items": [{"n": 52, "type": "fill_in", "prompt": "Earth is round because of ______—everything attracts everything else, so any “corners” were pulled in to form a giant sphere.", "blanks": 1}, {"n": 53, "type": "fill_in", "prompt": "The deviation of an orbiting object from its path caused by the action of an additional center of force is called a ______.", "blanks": 1}, {"n": 54, "type": "true_false", "prompt": "The planet Neptune was discovered by analyzing unexplained perturbations in the orbit of Uranus."}, {"n": 55, "type": "true_false", "prompt": "Astronomers now regard Pluto as a dwarf planet and not a full-fledged planet."}, {"n": 56, "type": "multiple_choice", "prompt": "According to current scientific understanding, the universe originated some 13.7 billion years ago in an event called", "options": [{"letter": "a", "text": "the Big Bang"}, {"letter": "b", "text": "the Big Crunch"}, {"letter": "c", "text": "a supernova"}]}, {"n": 57, "type": "short_answer", "prompt": "According to recent evidence, what makes up most of the universe?"}]}]$ch13$::jsonb,
$ch13${"1": ["inertia"], "2": ["gravity"], "3": "true", "4": "b", "5": ["cannonball"], "6": ["tangential"], "7": "true", "8": "false", "9": "b", "10": {"model": "The moon is actually falling toward Earth but has great enough tangential velocity that it falls around Earth instead of into it."}, "11": ["copernican"], "12": ["fall"], "13": "true", "14": "b", "15": ["universal"], "16": ["centers"], "17": "true", "18": "true", "19": "a", "20": {"model": "Once the value of G was known, the mass of Earth could easily be calculated from the 10-N force Earth exerts on a 1-kilogram mass at its surface."}, "21": ["inverse", "square"], "22": ["0.25"], "23": "false", "24": "b", "25": {"model": "Light, radiation, and sound all weaken by the inverse-square law as they spread from a localized source."}, "26": ["force"], "27": ["closer"], "28": "true", "29": "b", "30": {"model": "Earth's gravitational field is strongest near Earth's surface and grows weaker at greater distances from Earth."}, "31": ["zero"], "32": ["45"], "33": "false", "34": "true", "35": "b", "36": ["weight"], "37": ["support"], "38": "true", "39": "b", "40": {"model": "By rotating—rotation effectively supplies a support force and nicely provides weight."}, "41": ["differences"], "42": ["spring", "neap"], "43": "true", "44": "false", "45": "b", "46": {"model": "No part of the lake is significantly closer to the moon than any other part, so there is no significant difference in the moon's pull across the lake."}, "47": ["fusion"], "48": ["light"], "49": "false", "50": "c", "51": {"model": "Matter streaming from a visible companion star emits X-rays as it accelerates toward the black hole, and stars near galactic centers speed around in tight orbits."}, "52": ["gravitation"], "53": ["perturbation"], "54": "true", "55": "true", "56": "a", "57": {"model": "Dark energy (about 73 percent) and dark matter (about 23 percent); ordinary matter makes up only about 4 percent."}}$ch13$::jsonb)
ON CONFLICT (chapter) DO UPDATE SET title=EXCLUDED.title, text_pdf_url=EXCLUDED.text_pdf_url, page_offset=EXCLUDED.page_offset, sections=EXCLUDED.sections, answer_key=EXCLUDED.answer_key, updated_at=now();

-- Chapter 14: Satellite Motion
INSERT INTO concept_exercises (chapter, title, text_pdf_url, page_offset, sections, answer_key)
VALUES (14, $ch14$Satellite Motion$ch14$, $ch14$https://ymszffulqmkqgvhioege.supabase.co/storage/v1/object/public/lesson-media/cpte14.pdf$ch14$, 261,
$ch14$[{"id": "14.1", "label": "Earth Satellites", "pageStart": 263, "pageEnd": 265, "items": [{"n": 1, "type": "fill_in", "prompt": "An Earth satellite is simply a ______ moving fast enough to fall continually around Earth rather than into it.", "blanks": 1}, {"n": 2, "type": "fill_in", "prompt": "Earth's surface drops a vertical distance of nearly ______ meters for every 8000 meters tangent to its surface.", "blanks": 1}, {"n": 3, "type": "true_false", "prompt": "A stone thrown fast enough to go a horizontal distance of 8000 meters during the 1 second it takes to fall 5 meters will orbit Earth."}, {"n": 4, "type": "true_false", "prompt": "A satellite must stay about 150 kilometers or more above Earth's surface to keep from burning up due to friction with the atmosphere."}, {"n": 5, "type": "multiple_choice", "prompt": "The orbital speed for close orbit about Earth is", "options": [{"letter": "a", "text": "8 km/s"}, {"letter": "b", "text": "11.2 km/s"}, {"letter": "c", "text": "29 km/s"}]}, {"n": 6, "type": "short_answer", "prompt": "What two rates determine how fast a stone must be thrown horizontally to orbit Earth?"}]}, {"id": "14.2", "label": "Circular Orbits", "pageStart": 265, "pageEnd": 267, "items": [{"n": 7, "type": "fill_in", "prompt": "A satellite in circular orbit is always moving ______ to the force of gravity, so its speed does not change.", "blanks": 1}, {"n": 8, "type": "fill_in", "prompt": "For a satellite close to Earth, the period—the time for a complete orbit—is about ______ minutes.", "blanks": 1}, {"n": 9, "type": "true_false", "prompt": "Communications satellites orbit at 6.5 Earth radii so that their 24-hour period matches Earth's rotation and they stay above the same place on the equator."}, {"n": 10, "type": "true_false", "prompt": "Gravity changes the speed of a satellite in circular orbit."}, {"n": 11, "type": "multiple_choice", "prompt": "The higher the orbit of a satellite,", "options": [{"letter": "a", "text": "the faster its speed and the shorter its period"}, {"letter": "b", "text": "the slower its speed and the longer its period"}, {"letter": "c", "text": "the slower its speed and the shorter its period"}]}, {"n": 12, "type": "short_answer", "prompt": "What idea did Newton not consider that made him pessimistic about people launching satellites?"}]}, {"id": "14.3", "label": "Elliptical Orbits", "pageStart": 267, "pageEnd": 268, "items": [{"n": 13, "type": "fill_in", "prompt": "A satellite in orbit around Earth traces an oval-shaped path called an ______.", "blanks": 1}, {"n": 14, "type": "fill_in", "prompt": "The two fixed points in an ellipse are called ______.", "blanks": 1}, {"n": 15, "type": "true_false", "prompt": "A circle is a special case of an ellipse, occurring when the two foci are together."}, {"n": 16, "type": "multiple_choice", "prompt": "When a satellite's initial speed is more than 8 km/s, it", "options": [{"letter": "a", "text": "stays on a circular path at constant speed"}, {"letter": "b", "text": "overshoots a circular path and moves away from Earth, losing speed"}, {"letter": "c", "text": "immediately falls straight back to Earth"}]}, {"n": 17, "type": "short_answer", "prompt": "Describe how a satellite's speed changes around an elliptical orbit."}]}, {"id": "14.4", "label": "Energy Conservation and Satellite Motion", "pageStart": 269, "pageEnd": 270, "items": [{"n": 18, "type": "fill_in", "prompt": "The point in a satellite's orbit farthest from the center of Earth is the ______; the point closest to the center of Earth is the ______.", "blanks": 2}, {"n": 19, "type": "fill_in", "prompt": "The sum of the KE and PE of a satellite is ______ at all points along an orbit.", "blanks": 1}, {"n": 20, "type": "true_false", "prompt": "In a circular orbit, both the PE and the KE of the satellite are constant everywhere along the orbit."}, {"n": 21, "type": "multiple_choice", "prompt": "In an elliptical orbit, the KE of a satellite is greatest at", "options": [{"letter": "a", "text": "the apogee"}, {"letter": "b", "text": "the perigee"}, {"letter": "c", "text": "every point equally"}]}, {"n": 22, "type": "short_answer", "prompt": "Why does a satellite's speed decrease as it moves from perigee toward apogee?"}]}, {"id": "14.5", "label": "Kepler's Laws of Planetary Motion", "pageStart": 270, "pageEnd": 272, "items": [{"n": 23, "type": "fill_in", "prompt": "Kepler's first law states that the path of each planet around the sun is an ellipse with the sun at one ______.", "blanks": 1}, {"n": 24, "type": "fill_in", "prompt": "Kepler analyzed the twenty years of planetary measurements made by the Danish astronomer Tycho ______.", "blanks": 1}, {"n": 25, "type": "true_false", "prompt": "Kepler's second law states that a line from the sun to a planet sweeps out equal areas of space in equal intervals of time."}, {"n": 26, "type": "true_false", "prompt": "Kepler understood that a satellite is simply a projectile under the influence of a gravitational force."}, {"n": 27, "type": "multiple_choice", "prompt": "Kepler's third law states that the square of a planet's orbital period is directly proportional to", "options": [{"letter": "a", "text": "the planet's mass"}, {"letter": "b", "text": "the cube of its average distance from the sun"}, {"letter": "c", "text": "its average orbital speed"}]}, {"n": 28, "type": "short_answer", "prompt": "Do Kepler's laws apply only to planets?"}]}, {"id": "14.6", "label": "Escape Speed", "pageStart": 272, "pageEnd": 275, "items": [{"n": 29, "type": "fill_in", "prompt": "The escape speed from the surface of Earth is ______ km/s.", "blanks": 1}, {"n": 30, "type": "fill_in", "prompt": "Pioneer 10 escaped the solar system by being whipped about by ______'s great gravitational field, picking up speed in the process.", "blanks": 1}, {"n": 31, "type": "true_false", "prompt": "A rocket launched vertically that quickly reaches 8 km/s will go into orbit around Earth."}, {"n": 32, "type": "true_false", "prompt": "If its engines can be sustained for long periods of time, a rocket could go to the moon without ever attaining 11.2 km/s."}, {"n": 33, "type": "multiple_choice", "prompt": "The escape speeds for different bodies refer to", "options": [{"letter": "a", "text": "the initial speed given by a brief thrust, after which there is no force to assist motion"}, {"letter": "b", "text": "the speed needed with continuous engine thrust"}, {"letter": "c", "text": "the speed of any satellite in circular orbit"}]}, {"n": 34, "type": "short_answer", "prompt": "How much PE does a 1-kilogram mass have when it is infinitely far from Earth, and what speed does that energy correspond to?"}]}]$ch14$::jsonb,
$ch14${"1": ["projectile"], "2": ["5"], "3": "true", "4": "true", "5": "a", "6": {"model": "The rate at which the stone falls and the rate at which Earth's surface curves away beneath it."}, "7": ["perpendicular"], "8": ["90"], "9": "true", "10": "false", "11": "b", "12": {"model": "Multistage rockets—rockets carried piggyback on other rockets that reach orbital speed by a succession of firings."}, "13": ["ellipse"], "14": ["foci"], "15": "true", "16": "b", "17": {"model": "It loses speed as it recedes from Earth, then regains that speed as it falls back, rejoining its path with the same speed it had initially—the cycle repeats."}, "18": ["apogee", "perigee"], "19": ["constant"], "20": "true", "21": "b", "22": {"model": "A component of gravitational force acts opposite to its direction of motion, so its speed and KE decrease until it reaches the apogee."}, "23": ["focus"], "24": ["brahe"], "25": "true", "26": "false", "27": "b", "28": {"model": "No—they apply also to moons or any satellite in orbit around any body."}, "29": ["11.2"], "30": ["jupiter"], "31": "false", "32": "true", "33": "a", "34": {"model": "About 62 million joules (62 MJ) per kilogram, which corresponds to a speed of 11.2 km/s."}}$ch14$::jsonb)
ON CONFLICT (chapter) DO UPDATE SET title=EXCLUDED.title, text_pdf_url=EXCLUDED.text_pdf_url, page_offset=EXCLUDED.page_offset, sections=EXCLUDED.sections, answer_key=EXCLUDED.answer_key, updated_at=now();

-- u2-d04: 11 blocks
UPDATE lessons SET content_blocks = $u2${"schemaVersion": 1, "dayType": "STANDARD", "blocks": [{"id": "b1", "type": "target", "statement": "I can write F = G·m₁·m₂/r², explain what each symbol means, and reason about how F changes when masses or distance change.", "targetId": "u2.k1-universal-gravitation"}, {"id": "b2", "type": "asteroid_thread", "whatWeKnow": "The asteroid feels gravity from the Sun and (weakly) Earth.", "connection": "THIS is the equation we've been building toward. The 1/r² geometry decides how steeply gravity grows as 2026-XJ approaches."}, {"id": "b3", "type": "prose", "markdown": "## The equation that runs the solar system\n\n**F = G · m₁ · m₂ / r²**\n\n- **F** — the gravitational force between the two masses (newtons)\n- **G** = 6.67 × 10⁻¹¹ N·m²/kg² — always the same. That's why we call it *universal*.\n- **m₁** — mass of one object (kg)\n- **m₂** — mass of the other object (kg)\n- **r** — distance between the **centers** of the two objects (meters)\n- **r²** — r SQUARED. Doubling r makes F drop to **1/4**. Tripling r makes F drop to **1/9**.\n\nEvery mass pulls on every other mass. Earth pulls the Moon; the Moon pulls Earth back (that's the tides). You pull on your neighbor — tiny, but real."}, {"id": "b4", "type": "vocab", "terms": [{"term": "Universal gravitation", "definition": "Every mass pulls on every other mass with a force F = G·m₁·m₂/r². Earth pulls the Moon; the Moon pulls Earth back (tides).", "cognate": "Sp. gravitación universal · Pt. gravitação universal"}]}, {"id": "b5", "type": "callout", "variant": "warning", "title": "r is between CENTERS", "markdown": "r is measured center-to-center, **not** surface-to-surface. For an Earth–asteroid calculation, r ≈ the gap between them **plus Earth's radius**."}, {"id": "b6", "type": "callout", "variant": "misconception", "title": "Gravity is not just 'Earth pulling things down'", "markdown": "Every **pair** of masses attracts. The reason you don't feel your neighbor's pull is the sizes involved: with human-scale masses, G·m₁·m₂ is microscopic. It takes a planet-sized m to make F noticeable."}, {"id": "b7", "type": "equation_sandbox", "capture": true, "prompt": "Explore F = G·m₁·m₂/r². Start with reasonable asteroid numbers, then test: what happens to F when you double r? Triple it? Double one of the masses? Write what you find.", "variables": [{"symbol": "G", "value": "6.67e-11", "unit": "N·m²/kg²"}, {"symbol": "m₁", "value": "5.97e24", "unit": "kg"}, {"symbol": "m₂", "value": "3.5e11", "unit": "kg"}, {"symbol": "r", "unit": "m"}]}, {"id": "b8", "type": "exit_ticket", "capture": true, "prompt": "If 2026-XJ doubles its distance from Earth, what happens to F_gravity? What if it triples its distance?", "frame": "At 2r, F drops to ___ of its old value. At 3r, F drops to ___. The pattern is called an ___-square law."}, {"id": "rd-ch13-a", "type": "callout", "variant": "note", "title": "Read & practice", "markdown": "Open the reader and read **13.1–13.4** (the falling apple, the falling moon, the falling Earth, Newton's law of universal gravitation). Answer the questions beside the reading as you go."}, {"id": "ce-ch13-a", "type": "concept_exercise", "capture": true, "chapter": 13, "title": "Universal Gravitation — read & practice", "sectionIds": ["13.1", "13.2", "13.3", "13.4"]}, {"id": "b9", "type": "marzano", "capture": true, "targetId": "u2.k1-universal-gravitation"}]}$u2$::jsonb, updated_at = now() WHERE slug = 'u2-d04';

-- u2-d05: 11 blocks
UPDATE lessons SET content_blocks = $u2${"schemaVersion": 1, "dayType": "STANDARD", "blocks": [{"id": "b1", "type": "target", "statement": "I can compute the gravitational force between two masses given their distance, and I can reason about how F scales when any input changes.", "targetId": "u2.s1-compute-gravitation"}, {"id": "b2", "type": "asteroid_thread", "whatWeKnow": "2026-XJ's mass: roughly 3.5 × 10¹¹ kg (estimate). Sun's mass: 1.99 × 10³⁰ kg.", "connection": "Today you compute real Earth–Moon, Earth–Sun, Earth–asteroid forces. The biggest force in 2026-XJ's life is the SUN."}, {"id": "b3", "type": "prose", "markdown": "## Calculation day — two skills, one equation\n\n**Skill 1 — compute.** Plug into F = G·m₁·m₂/r² with scientific notation. Keep the powers of ten organized: multiply the front numbers, add the exponents on top, subtract the bottom's.\n\n**Skill 2 — scale.** When only r changes, don't recompute from scratch. Use the 1/r² rule:\n\n- r × 2 → F × ¼\n- r × 3 → F × 1/9\n- r × ½ → F × **4**\n\nScaling is faster than recomputing — and it's the skill the transfer task rewards."}, {"id": "b4", "type": "worked_example", "prompt": "Find F between Earth (m₁ = 5.97 × 10²⁴ kg) and Moon (m₂ = 7.35 × 10²² kg) at r = 3.84 × 10⁸ m.", "given": "m₁ = 5.97×10²⁴ kg · m₂ = 7.35×10²² kg · r = 3.84×10⁸ m · G = 6.67×10⁻¹¹", "equation": "F = G·m₁·m₂ / r²", "work": "F = (6.67×10⁻¹¹)(5.97×10²⁴)(7.35×10²²) / (3.84×10⁸)²\nF = (2.93×10³⁷) / (1.47×10¹⁷)\nF ≈ 1.99 × 10²⁰ N", "answer": "≈ 2.0 × 10²⁰ N — gigantic, but felt by a gigantic Moon."}, {"id": "b5", "type": "gewa", "capture": true, "prompt": "Find F between Earth (m₁ = 5.97 × 10²⁴ kg) and 2026-XJ (m₂ = 3.5 × 10¹¹ kg) at r = 1.0 × 10¹⁰ m (about 26 lunar distances).", "givenHint": "Both masses, the distance r, and G = 6.67 × 10⁻¹¹.", "equationHint": "Newton's universal gravitation — same recipe as the worked example.", "equationIds": ["gravitation", "weight", "newton-2nd", "avg-speed", "displacement"]}, {"id": "b6", "type": "gewa", "capture": true, "prompt": "If 2026-XJ moves to r = 5.0 × 10⁹ m (HALF the previous distance), what is F now? You can SCALE rather than recompute: F_new = F_old × (factor).", "givenHint": "Your previous answer for F, and the fact that r was cut in half.", "equationHint": "r × ½ → F × 4. Scale your previous answer.", "equationIds": ["gravitation"]}, {"id": "b7", "type": "exit_ticket", "capture": true, "prompt": "If 2026-XJ is currently at 5 lunar distances from Earth and gets to 1 lunar distance, how many times larger is the gravitational force?", "frame": "r shrinks by a factor of ___, so F grows by a factor of ___² = ___."}, {"id": "b8", "type": "marzano", "capture": true, "targetId": "u2.s1-compute-gravitation"}, {"id": "rd-ch13-b", "type": "callout", "variant": "note", "title": "Read & practice", "markdown": "Open the reader and read **13.5–13.11** (the inverse-square law, gravitational fields, weight and weightlessness, ocean tides, black holes, and gravity's reach across the universe). Answer the questions beside the reading as you go."}, {"id": "ce-ch13-b", "type": "concept_exercise", "capture": true, "chapter": 13, "title": "Universal Gravitation — read & practice", "sectionIds": ["13.5", "13.6", "13.7", "13.8", "13.9", "13.10", "13.11"]}, {"id": "b9", "type": "marzano", "capture": true, "targetId": "u2.r1-scale-f"}]}$u2$::jsonb, updated_at = now() WHERE slug = 'u2-d05';

-- u2-d09: 12 blocks
UPDATE lessons SET content_blocks = $u2${"schemaVersion": 1, "dayType": "STANDARD", "blocks": [{"id": "b1", "type": "target", "statement": "I can decompose a projectile's motion into independent horizontal and vertical pieces, and I can explain why a side-pushed ball and a dropped ball hit the ground at the same time.", "targetId": "u2.k3-projectile-independence"}, {"id": "b2", "type": "asteroid_thread", "whatWeKnow": "An asteroid in flight is technically a projectile — gravity bends its path.", "connection": "What you learn about projectiles in 3 days scales straight up to orbits. The math is the same; only the distances grow."}, {"id": "b3", "type": "prose", "markdown": "## Two motions, one object\n\nA projectile's motion splits into two **independent** pieces:\n\n- **Horizontal:** x = vₓ · t — horizontal velocity **never changes** (no horizontal force).\n- **Vertical:** y = y₀ − ½·g·t² — vertical velocity changes at g per second (gravity acts here).\n\nThe two pieces don't talk to each other. **Time is the only link** between them."}, {"id": "b4", "type": "vocab", "terms": [{"term": "Projectile", "definition": "Any object moving under gravity alone after launch — no engine, no air force. A thrown baseball. A horizontally-fired bullet. An asteroid in free fall.", "cognate": "Sp. proyectil · Pt. projétil · HC pwojektil"}]}, {"id": "b5", "type": "callout", "variant": "note", "title": "The drop-and-push race", "markdown": "Drop one ball. Push another sideways at the **same instant**. They hit the ground at the **SAME time**. Time is set by the VERTICAL motion alone — the sideways push changes *where* it lands, not *when*."}, {"id": "b6", "type": "callout", "variant": "tip", "title": "In class today — monkey and hunter", "markdown": "We watched the classic monkey-and-hunter setup: aim straight at the target, and if the target drops the instant you fire, you ALWAYS hit it — both fall at the same g. Run the simulation below and test which prediction survives."}, {"id": "b7", "type": "sim_embed", "simulationSlug": "monkey-hunter"}, {"id": "b8", "type": "sketch", "capture": true, "instruction": "Draw the dropped ball and the side-pushed ball at three moments (t = 0, 1 s, 2 s). For the pushed ball, label vₓ at each moment (it never changes) and v_y at each moment (it grows by ~10 m/s each second).", "prompts": ["Both balls at the SAME height at each moment.", "vₓ labels: same value all three times.", "v_y labels: 0, ~10, ~20 m/s."]}, {"id": "b9", "type": "exit_ticket", "capture": true, "prompt": "Why does a side-pushed ball NOT take longer to fall than a ball that's just dropped? Use the word 'independent' in your answer.", "frame": "The horizontal and vertical motions are ___, so the sideways push changes ___ but not ___."}, {"id": "rd-ch05-a", "type": "callout", "variant": "note", "title": "Read & practice", "markdown": "Open the reader and read **5.1–5.4** (vectors and scalars, velocity vectors, components of vectors, and what makes a projectile). Answer the questions beside the reading as you go."}, {"id": "ce-ch05-a", "type": "concept_exercise", "capture": true, "chapter": 5, "title": "Projectile Motion — read & practice", "sectionIds": ["5.1", "5.2", "5.3", "5.4"]}, {"id": "b10", "type": "marzano", "capture": true, "targetId": "u2.k3-projectile-independence"}]}$u2$::jsonb, updated_at = now() WHERE slug = 'u2-d09';

-- u2-d10: 13 blocks
UPDATE lessons SET content_blocks = $u2${"schemaVersion": 1, "dayType": "STANDARD", "blocks": [{"id": "b1", "type": "target", "statement": "I can solve a horizontal-launch projectile problem: find fall time from height, then find horizontal range.", "targetId": "u2.s2-projectile-calc"}, {"id": "b2", "type": "asteroid_thread", "whatWeKnow": "2026-XJ has both horizontal and vertical velocity (with respect to Earth).", "connection": "Cliff problems are the small-scale version. The recipe (find t first, then x) is the same recipe orbit problems use."}, {"id": "b3", "type": "prose", "markdown": "## The two-step recipe\n\nEvery horizontal-launch problem is the same two steps, in the same order:\n\n1. **Find time from the VERTICAL motion:** h = ½·g·t² → t = √(2h/g). The height alone decides how long it's in the air.\n2. **Find range from the HORIZONTAL motion:** x = vₓ·t. Plug in the t you just found.\n\nNever the other way around. The horizontal motion can't tell you the time — vₓ never changes, so it has no clock in it."}, {"id": "b4", "type": "callout", "variant": "tip", "title": "Strategy every time", "markdown": "**FIND TIME FIRST** from the vertical motion. Then plug t into x = vₓ·t."}, {"id": "b5", "type": "callout", "variant": "tip", "title": "Test it in the simulation", "markdown": "Launch a few projectiles below. Change the height and watch the fall time change; change vₓ and watch the range change while the fall time stays put. That asymmetry IS the independence from yesterday."}, {"id": "b6", "type": "sim_embed", "simulationSlug": "projectile-motion"}, {"id": "b7", "type": "worked_example", "prompt": "A ball is fired horizontally from a 5 m cliff at vₓ = 10 m/s. (a) How long until it hits the ground? (b) How far from the cliff base?", "given": "h = 5 m · vₓ = 10 m/s · g = 9.81 m/s²", "equation": "(1) h = ½·g·t²      (2) x = vₓ·t", "work": "(1) 5 = ½·(9.81)·t² → t² = 10/9.81 → t ≈ 1.01 s\n(2) x = 10 × 1.01 ≈ 10.1 m", "answer": "t ≈ 1.0 s, lands ≈ 10 m from the cliff."}, {"id": "b8", "type": "sketch", "capture": true, "instruction": "Pick your own numbers for cliff height h and launch speed vₓ. Draw the cliff, the launch arrow, and trace the parabola lightly. Label the range x where it lands.", "prompts": ["Label h on the cliff and vₓ on the launch arrow.", "The path curves down more and more steeply — a parabola.", "Label the range x along the ground."]}, {"id": "b9", "type": "gewa", "capture": true, "prompt": "A ball is fired horizontally from a 45 m cliff at vₓ = 15 m/s. (a) Find fall time. (b) Find horizontal range.", "givenHint": "h = 45 m, vₓ = 15 m/s, g = 9.81 m/s².", "equationHint": "Step 1: h = ½·g·t² gives the time. Step 2: x = vₓ·t gives the range.", "equationOptions": ["h = ½·g·t²", "x = vₓ·t", "vₓ = v·cos θ", "v_y = v·sin θ"]}, {"id": "b10", "type": "exit_ticket", "capture": true, "prompt": "From a 20 m cliff at vₓ = 8 m/s, where does the ball land? Show both steps.", "frame": "Step 1 (time from height): t ≈ ___ s. Step 2 (range): x = 8 × ___ ≈ ___ m."}, {"id": "rd-ch05-b", "type": "callout", "variant": "note", "title": "Read & practice", "markdown": "Open the reader and read **5.5–5.6** (projectiles launched horizontally and projectiles launched at an angle). Answer the questions beside the reading as you go."}, {"id": "ce-ch05-b", "type": "concept_exercise", "capture": true, "chapter": 5, "title": "Projectile Motion — read & practice", "sectionIds": ["5.5", "5.6"]}, {"id": "b11", "type": "marzano", "capture": true, "targetId": "u2.s2-projectile-calc"}]}$u2$::jsonb, updated_at = now() WHERE slug = 'u2-d10';

-- u2-d12: 12 blocks
UPDATE lessons SET content_blocks = $u2${"schemaVersion": 1, "dayType": "STANDARD", "blocks": [{"id": "b1", "type": "target", "statement": "I can compute a_c = v²/r and F_c = m·v²/r for an object in circular motion and explain why F_c always points toward the center.", "targetId": "u2.s3-centripetal-calc"}, {"id": "b2", "type": "asteroid_thread", "whatWeKnow": "An orbit IS circular motion. The force that holds an orbit is gravity.", "connection": "Today we get the centripetal math. Tomorrow we connect it to gravity and discover that orbits ARE FALLING."}, {"id": "b3", "type": "prose", "markdown": "## Turning is accelerating\n\nAn object moving in a circle at constant **speed** is still accelerating — its **direction** is changing every instant. That acceleration points toward the center:\n\n- **a_c = v² / r** — centripetal acceleration\n- **F_c = m·v² / r** — the net inward force required to keep the circle\n\nFaster (bigger v) or tighter (smaller r) → more force needed. If the available force can't supply F_c, the object leaves the circle."}, {"id": "b4", "type": "vocab", "terms": [{"term": "Centripetal force", "definition": "The NET inward force that keeps an object on a circular path; F_c = m·v²/r. A car turning a corner: friction is the centripetal force. A satellite orbiting: gravity is.", "cognate": "Sp. fuerza centrípeta · Pt. força centrípeta · HC fòs santipèt"}]}, {"id": "b5", "type": "callout", "variant": "misconception", "title": "Centripetal force is a ROLE, not a new force", "markdown": "It's not a new kind of force. It's the role played by an **existing** force — friction, gravity, tension — whenever that force points toward the center. And when the string cuts, the ball flies along the **TANGENT** — not outward. There's no 'centrifugal force' pushing it out; the inward force just disappears."}, {"id": "b6", "type": "diagram", "kind": "vectors", "title": "Ball on a string — the two arrows that matter", "caption": "v points along the tangent (where the ball would go if released). F_c points inward along the string. If the string cuts, the ball follows v — straight out along the tangent.", "genPrompt": "A ball in circular motion: velocity vector tangent to the circle, centripetal force vector pointing toward the center, 90 degrees apart.", "vectors": [{"label": "v (tangent)", "angle": 0, "mag": 80}, {"label": "F_c (toward center)", "angle": 90, "mag": 60}], "showResultant": false}, {"id": "b7", "type": "worked_example", "prompt": "A 1500 kg car rounds a 50 m radius curve at 20 m/s. What centripetal force must friction provide?", "given": "m = 1500 kg · v = 20 m/s · r = 50 m", "equation": "F_c = m·v² / r", "work": "F_c = 1500 × (20)² / 50\nF_c = 1500 × 400 / 50\nF_c = 12,000 N", "answer": "12,000 N inward. Friction has to provide all of it — if it can't, the car skids out."}, {"id": "b8", "type": "gewa", "capture": true, "prompt": "A 0.2 kg ball moves in a horizontal circle at 4 m/s on a 1 m string. What is the centripetal force? What provides it?", "givenHint": "m = 0.2 kg, v = 4 m/s, r = 1 m. Name the force playing the centripetal role in your Answer.", "equationHint": "F_c = m·v²/r.", "equationOptions": ["F_c = m·v²/r", "a_c = v²/r", "F = m·g", "F = G·m₁·m₂/r²"]}, {"id": "b9", "type": "exit_ticket", "capture": true, "prompt": "The string cuts while the ball is circling. Which way does the ball fly, and why is 'it gets flung outward by centrifugal force' the wrong explanation?", "frame": "The ball flies along the ___, because the only thing that changed is that the ___ force disappeared."}, {"id": "rd-ch10", "type": "callout", "variant": "note", "title": "Read & practice", "markdown": "Open the reader and read **10.1–10.5** (rotation vs. revolution, rotational and tangential speed, centripetal force, and why 'centrifugal force' isn't a true force). Answer the questions beside the reading as you go."}, {"id": "ce-ch10", "type": "concept_exercise", "capture": true, "chapter": 10, "title": "Circular Motion — read & practice", "sectionIds": ["10.1", "10.2", "10.3", "10.4", "10.5"]}, {"id": "b10", "type": "marzano", "capture": true, "targetId": "u2.s3-centripetal-calc"}]}$u2$::jsonb, updated_at = now() WHERE slug = 'u2-d12';

-- u2-d13: 13 blocks
UPDATE lessons SET content_blocks = $u2${"schemaVersion": 1, "dayType": "LAB", "blocks": [{"id": "b1", "type": "target", "statement": "I can explain an orbit as continuous free fall, and I can use the PhET Gravity and Orbits sim to find what launch speed produces a circular orbit at a given altitude.", "targetId": "u2.k5-orbit-free-fall"}, {"id": "b2", "type": "asteroid_thread", "whatWeKnow": "Two orbits (Earth's and 2026-XJ's) can cross. The question is timing.", "connection": "Today we discover that an orbit IS falling — at exactly the speed that lets the ground curve away as fast as you fall toward it."}, {"id": "b3", "type": "prose", "markdown": "## Newton's cannon\n\nNewton's thought experiment: fire a cannonball horizontally from a tall mountain.\n\n- Fire it **slow** → it falls and hits the ground nearby.\n- Fire it **faster** → it still falls, but lands farther away.\n- Fire it at exactly the right speed → it falls toward Earth at the same rate the Earth's surface **curves away beneath it**. It falls forever and never lands.\n\nThat last case **is an orbit**. Nothing is holding the object up. It is falling the entire time — which is exactly why astronauts inside it float."}, {"id": "b4", "type": "callout", "variant": "note", "title": "Investigation 2.2 — PhET Gravity and Orbits", "markdown": "**Driving question:** What launch speed produces a CIRCULAR orbit at a given altitude?\n\n**Equipment:** laptop with the PhET *Gravity and Orbits* sim ([phet.colorado.edu](https://phet.colorado.edu/sims/html/gravity-and-orbits/latest/gravity-and-orbits_en.html)) · calculator · today's data table.\n\n**How this lab serves the year's question:** 2026-XJ is on a Sun-orbit. The same v_orbit equation applies — only the central mass changes."}, {"id": "b5", "type": "procedure", "title": "What you do", "steps": ["Open PhET **Gravity and Orbits**. Place a satellite near Earth at a chosen altitude.", "Try a small launch velocity. What happens? (Crashes.)", "Increase the velocity. Find a speed that makes a **CIRCULAR** orbit.", "Then compute v_orbit = √(G·M/r) for that altitude. Compare."]}, {"id": "b6", "type": "data_table", "capture": true, "columns": ["Trial", "Altitude (km)", "Launch v (m/s)", "Result (crash / oval / circle / escape)"], "rows": 5, "plot": false, "patternPrompt": "What pattern connects launch speed to the shape of the path?"}, {"id": "b7", "type": "sketch", "capture": true, "instruction": "Draw Earth and three cannonball paths from the same launch point: label which is 'slow' (crashes near), which is 'faster' (crashes far), and which is 'orbit speed' (never lands). Then write the key idea sentence using the words 'falling' and 'horizontal'.", "prompts": ["Three paths, one launch point.", "Labels: slow / faster / orbit speed.", "Key sentence with 'falling' and 'horizontal'."]}, {"id": "b8", "type": "worked_example", "prompt": "For a circular orbit, gravity IS the centripetal force. Set F_gravity = F_centripetal and solve for v. Show every step.", "given": "Circular orbit at radius r around mass M", "equation": "F_g = G·M·m/r² ; F_c = m·v²/r ; set them equal", "work": "G·M·m / r² = m·v² / r\nG·M / r² = v² / r         (cancel m)\nG·M / r = v²              (multiply both sides by r)\nv = √(G·M / r)", "answer": "v_orbit = √(G·M / r). The orbit speed depends on the CENTRAL mass and the radius — not on the satellite's mass."}, {"id": "b9", "type": "observation", "capture": true, "patternPrompt": "What was the launch speed for a CLEAN circular orbit at 400 km altitude in the sim?", "interpretPrompt": "Compare your sim value to v_orbit = √(G·M_Earth / r) at r = R_Earth + 400 km. Do they match? And the asteroid connection: how does this serve the year's question?", "frame": "The launch speed for a circular orbit at 400 km is about ___ m/s. Theory predicts ___ m/s. The sim agrees ___."}, {"id": "b10", "type": "exit_ticket", "capture": true, "prompt": "In 2-3 sentences, explain why the ISS doesn't fall straight down. Use the words 'falling', 'horizontal', and 'curves away'.", "frame": "The ISS IS falling — but it also moves ___ so fast that the Earth ___ beneath it as fast as it falls."}, {"id": "rd-ch14-a", "type": "callout", "variant": "note", "title": "Read & practice", "markdown": "Open the reader and read **14.1–14.2** (what makes an Earth satellite and why a circular orbit holds constant speed). Answer the questions beside the reading as you go."}, {"id": "ce-ch14-a", "type": "concept_exercise", "capture": true, "chapter": 14, "title": "Satellite Motion — read & practice", "sectionIds": ["14.1", "14.2"]}, {"id": "b11", "type": "marzano", "capture": true, "targetId": "u2.k5-orbit-free-fall"}]}$u2$::jsonb, updated_at = now() WHERE slug = 'u2-d13';

-- u2-d14: 12 blocks
UPDATE lessons SET content_blocks = $u2${"schemaVersion": 1, "dayType": "STANDARD", "blocks": [{"id": "b1", "type": "target", "statement": "I can state Kepler's three laws in my own words and use Kepler's third law to compare orbital periods.", "targetId": "u2.k4-keplers-laws"}, {"id": "b2", "type": "asteroid_thread", "whatWeKnow": "2026-XJ's semi-major axis a ≈ 1.42 AU (refined orbit).", "connection": "Kepler's third law gives 2026-XJ's PERIOD — and that's the timing we need to answer Phase 5's question: WHEN does it next cross Earth's orbit?"}, {"id": "b3", "type": "prose", "markdown": "## Kepler's three laws, plainly\n\n1. **Orbits are ellipses**, with the central body at one focus (not at the center).\n2. **Equal areas in equal times** — an orbiting body sweeps out area at a steady rate. Near the Sun it moves FAST (perihelion); far from the Sun it moves SLOW (aphelion).\n3. **T² = a³** — for Sun-orbits with T in years and a in AU. Bigger orbit → much longer year, because T² grows as a³.\n\nKepler found these from data alone, decades before Newton explained WHY with universal gravitation."}, {"id": "b4", "type": "vocab", "terms": [{"term": "Ellipse", "definition": "An oval-shaped closed curve with TWO foci. Every planet's orbit is an ellipse with the central body at one focus. Earth's orbit is nearly circular (e ≈ 0.017); a comet's can be e ≈ 0.9.", "cognate": "Sp. elipse · Pt. elipse · HC elips"}, {"term": "Period (T)", "definition": "The time for one full orbit. Earth's period around the Sun = 1 year. Moon's period around Earth ≈ 27.3 days. A longer period means a longer orbit, not a slower object.", "cognate": "Sp. periodo · Pt. período · HC peryòd"}]}, {"id": "b5", "type": "callout", "variant": "misconception", "title": "Two foci, one Sun", "markdown": "An ellipse has TWO foci. The central body sits at **one** of them — not at the center of the oval. The other focus is empty space."}, {"id": "b6", "type": "sketch", "capture": true, "instruction": "Draw an elliptical orbit with the Sun at one focus (off-center!). MARK the point where the object moves FASTEST (perihelion — closest to the Sun) and the point where it moves SLOWEST (aphelion — farthest). Then write WHY in one sentence (think: equal areas in equal times).", "prompts": ["Sun at one focus, visibly off-center.", "Label perihelion (fastest) and aphelion (slowest).", "One sentence: why faster when closer?"]}, {"id": "b7", "type": "worked_example", "prompt": "Mars has a semi-major axis a = 1.52 AU. Find its period in years using Kepler's third law.", "given": "a = 1.52 AU · use T² = a³ (Sun-orbit, T in years)", "equation": "T² = a³ → T = √(a³)", "work": "T² = (1.52)³ = 3.51\nT = √3.51 ≈ 1.87 years", "answer": "≈ 1.87 Earth-years. (Real value: 1.88. Match.)"}, {"id": "b8", "type": "gewa", "capture": true, "prompt": "2026-XJ has a = 1.42 AU. Find its period in years. (This number tells us how often it could return to its current location.)", "givenHint": "a = 1.42 AU. Sun-orbit, so T² = a³ works directly with T in years.", "equationHint": "Cube a, then square-root: T = √(a³).", "equationOptions": ["T² = a³", "v = √(G·M/r)", "F = G·m₁·m₂/r²", "F_c = m·v²/r"]}, {"id": "b9", "type": "exit_ticket", "capture": true, "prompt": "Write each of Kepler's three laws in ONE sentence in your own words.", "frame": "1) Orbits are ___. 2) Objects sweep ___ in equal times, so they move faster when ___. 3) T² = ___ for Sun-orbits."}, {"id": "rd-ch14-b", "type": "callout", "variant": "note", "title": "Read & practice", "markdown": "Open the reader and read **14.3–14.6** (elliptical orbits, energy conservation in orbit, Kepler's laws, and escape speed). Answer the questions beside the reading as you go."}, {"id": "ce-ch14-b", "type": "concept_exercise", "capture": true, "chapter": 14, "title": "Satellite Motion — read & practice", "sectionIds": ["14.3", "14.4", "14.5", "14.6"]}, {"id": "b10", "type": "marzano", "capture": true, "targetId": "u2.k4-keplers-laws"}]}$u2$::jsonb, updated_at = now() WHERE slug = 'u2-d14';

COMMIT;
